import { useState, useEffect } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [zoom, setZoom] = useState(false);
  const [animatedScore, setAnimatedScore] = useState(0);
  const [darkMode, setDarkMode] = useState(false);
  const [adminMode, setAdminMode] = useState(false);
  const [adminNote, setAdminNote] = useState("");

  const claimId = `CLM-${Date.now()}`;

  /* ---------------- Fraud Score Animation ---------------- */
  useEffect(() => {
    if (result) {
      let start = 0;
      const end = result.fraud_confidence_score || 0;
      const duration = 1000;
      const stepTime = 20;
      const step = (end - start) / (duration / stepTime);

      const interval = setInterval(() => {
        start += step;
        if (start >= end) {
          start = end;
          clearInterval(interval);
        }
        setAnimatedScore(Math.round(start));
      }, stepTime);
    }
  }, [result]);

  /* ---------------- Helpers ---------------- */

  const riskLevel = (score) => {
    if (score <= 40) return "Low Risk";
    if (score <= 75) return "Medium Risk";
    return "High Risk";
  };

  const gaugeColor = (score) => {
    if (score <= 50) return "#22c55e";
    if (score <= 80) return "#f59e0b";
    return "#ef4444";
  };

  const verdictColor = (verdict) => {
    if (!verdict) return "#555";
    if (verdict.toLowerCase() === "fraud") return "#ef4444";
    if (verdict.toLowerCase() === "suspicious") return "#f59e0b";
    return "#22c55e";
  };

  /* ---------------- File Handling ---------------- */

  const handleFileChange = (e) => {
    const selected = e.target.files[0];
    if (!selected) return;

    setFile(selected);
    setPreview(URL.createObjectURL(selected));
    setResult(null);
    setError(null);
    setAnimatedScore(0);
  };

  const handleUpload = async () => {
    if (!file) return setError("Please select an image first.");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);
    setResult(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });

      if (!response.ok) throw new Error("Server error");

      const data = await response.json();
      setResult(data);
    } catch (err) {
      setError(err.message || "Something went wrong!");
    }

    setLoading(false);
  };

  const handleReset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
    setZoom(false);
    setAnimatedScore(0);
  };

  /* ---------------- Professional HTML Report ---------------- */

  const downloadReport = () => {
    if (!result) return;

    const htmlContent = `
    <html>
      <head>
        <title>ClaimPilot Report</title>
        <style>
          body { font-family: Arial; padding: 40px; }
          h1 { color: #1e40af; }
          .section { margin-top: 25px; }
          .highlight { font-weight: bold; }
        </style>
      </head>
      <body>
        <h1>ClaimPilot AI Audit Report</h1>
        <p><strong>Claim ID:</strong> ${claimId}</p>
        <p><strong>Date:</strong> ${new Date().toLocaleString()}</p>

        <div class="section">
          <h3>Total Estimate</h3>
          <p class="highlight">PKR ${result.total_estimate_pkr}</p>
        </div>

        <div class="section">
          <h3>Fraud Score</h3>
          <p class="highlight">${result.fraud_confidence_score}% (${riskLevel(
      result.fraud_confidence_score
    )})</p>
        </div>

        <div class="section">
          <h3>Verdict</h3>
          <p>${result.verdict}</p>
        </div>

        <div class="section">
          <h3>Damaged Parts</h3>
          <ul>
            ${(result.damaged_parts || [])
              .map((p) => `<li>${p}</li>`)
              .join("")}
          </ul>
        </div>

        <div class="section">
          <h3>Admin Notes</h3>
          <p>${adminNote || "N/A"}</p>
        </div>
      </body>
    </html>
    `;

    const blob = new Blob([htmlContent], { type: "text/html" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `ClaimPilot_Report_${claimId}.html`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const theme = darkMode ? darkStyles : styles;

  return (
    <div style={theme.page}>
      <div style={theme.container}>
        <header style={theme.header}>
          <h1 style={theme.logo}>ClaimPilot AI</h1>
          <p style={theme.tagline}>
            Intelligent Vehicle Damage Assessment & Fraud Detection
          </p>

          <div style={{ marginTop: 15 }}>
            <button style={theme.toggleBtn} onClick={() => setDarkMode(!darkMode)}>
              {darkMode ? "Light Mode" : "Dark Mode"}
            </button>

            <button
              style={{ ...theme.toggleBtn, marginLeft: 10 }}
              onClick={() => setAdminMode(!adminMode)}
            >
              {adminMode ? "User Mode" : "Admin Mode"}
            </button>
          </div>
        </header>

        {/* Upload Section */}
        <div
          style={theme.uploadCard}
          onDragOver={(e) => e.preventDefault()}
          onDrop={(e) => {
            e.preventDefault();
            handleFileChange({ target: { files: [e.dataTransfer.files[0]] } });
          }}
        >
          {preview && (
            <img
              src={preview}
              alt="preview"
              style={zoom ? theme.previewZoom : theme.preview}
              onClick={() => setZoom(!zoom)}
            />
          )}

          <label style={theme.uploadLabel}>
            {file ? file.name : "Click or Drag Image Here"}
            <input
              type="file"
              accept="image/*"
              style={{ display: "none" }}
              onChange={handleFileChange}
            />
          </label>

          <div style={{ display: "flex", gap: 10, justifyContent: "center" }}>
            <button
              onClick={handleUpload}
              disabled={loading}
              style={theme.primaryBtn}
            >
              {loading ? "Analyzing..." : "Run AI Audit"}
            </button>

            {file && (
              <button onClick={handleReset} style={theme.resetBtn}>
                Reset
              </button>
            )}
          </div>

          {error && <p style={theme.error}>{error}</p>}
        </div>

        {/* Result Section */}
        {result && (
          <div style={theme.resultCard}>
            <h2>Audit Summary</h2>

            <h3>PKR {result.total_estimate_pkr}</h3>

            <p
              style={{
                color: gaugeColor(animatedScore),
                fontWeight: "bold",
              }}
            >
              Fraud Score: {animatedScore}% ({riskLevel(animatedScore)})
            </p>

            <p style={{ color: verdictColor(result.verdict) }}>
              Verdict: {result.verdict}
            </p>

            {adminMode && (
              <div style={{ marginTop: 20 }}>
                <h3>Admin Review</h3>
                <textarea
                  value={adminNote}
                  onChange={(e) => setAdminNote(e.target.value)}
                  placeholder="Write internal notes..."
                  style={theme.textarea}
                />
              </div>
            )}

            <button onClick={downloadReport} style={theme.downloadBtn}>
              Download Professional Report
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

/* ---------------- Light Theme ---------------- */

const styles = {
  page: { minHeight: "100vh", background: "#f3f6fb", padding: 40 },
  container: { maxWidth: 1000, margin: "auto" },
  header: { textAlign: "center", marginBottom: 40 },
  logo: { fontSize: 38, fontWeight: 700 },
  tagline: { color: "#555" },
  uploadCard: {
    background: "#fff",
    padding: 30,
    borderRadius: 20,
    boxShadow: "0 15px 35px rgba(0,0,0,0.05)",
    marginBottom: 30,
  },
  uploadLabel: {
    display: "block",
    border: "2px dashed #ccc",
    padding: 25,
    borderRadius: 12,
    cursor: "pointer",
    marginBottom: 20,
    textAlign: "center",
  },
  preview: {
    width: "100%",
    maxHeight: 300,
    objectFit: "cover",
    borderRadius: 12,
    marginBottom: 15,
  },
  previewZoom: {
    width: "100%",
    maxHeight: 600,
    objectFit: "contain",
    borderRadius: 12,
    marginBottom: 15,
  },
  primaryBtn: {
    padding: "12px 25px",
    background: "#1e40af",
    color: "#fff",
    border: "none",
    borderRadius: 8,
    cursor: "pointer",
  },
  resetBtn: {
    padding: "12px 25px",
    background: "#ef4444",
    color: "#fff",
    border: "none",
    borderRadius: 8,
    cursor: "pointer",
  },
  resultCard: {
    background: "#fff",
    padding: 30,
    borderRadius: 20,
    boxShadow: "0 15px 35px rgba(0,0,0,0.05)",
  },
  downloadBtn: {
    marginTop: 20,
    padding: "12px 25px",
    background: "#22c55e",
    color: "#fff",
    border: "none",
    borderRadius: 8,
    cursor: "pointer",
  },
  toggleBtn: {
    padding: "8px 15px",
    borderRadius: 8,
    border: "none",
    cursor: "pointer",
  },
  textarea: {
    width: "100%",
    height: 90,
    marginTop: 10,
    padding: 10,
  },
  error: { color: "red", marginTop: 10 },
};

/* ---------------- Dark Theme ---------------- */

const darkStyles = {
  ...styles,
  page: { minHeight: "100vh", background: "#0f172a", padding: 40, color: "#fff" },
  uploadCard: { ...styles.uploadCard, background: "#1e293b" },
  resultCard: { ...styles.resultCard, background: "#1e293b" },
};

export default App;
